package org.apache.commons.compress.archivers.tar;

import org.junit.runner.RunWith;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.compress.archivers.tar.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
    // This is just a runner class for Cucumber tests
}

package org.apache.commons.compress.archivers.tar.steps;

import io.cucumber.java.Before;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.compress.archivers.tar.TarArchiveEntry;
import org.apache.commons.compress.archivers.tar.TarArchiveOutputStream;
import org.apache.commons.compress.archivers.tar.TarConstants;

import java.io.ByteArrayOutputStream;
import java.io.IOException;

import static org.junit.Assert.*;

public class StepDefs {
    private TarArchiveOutputStream tarOutputStream;
    private ByteArrayOutputStream byteArrayOutputStream;
    private TarArchiveEntry entry;

    @Before
    public void setUp() {
        byteArrayOutputStream = new ByteArrayOutputStream();
        tarOutputStream = new TarArchiveOutputStream(byteArrayOutputStream);
        // Set the long file mode to POSIX for handling long file names properly
        tarOutputStream.setLongFileMode(TarConstants.LONGFILE_POSIX);
    }

    @Given("a TarArchiveOutputStream configured with POSIX compatibility")
    public void a_TarArchiveOutputStream_configured_with_POSIX_compatibility() {
        // This is already set up in the @Before method
        assertNotNull(tarOutputStream);
    }

    @Given("the stream is set to add PAX headers for non-ASCII names")
    public void the_stream_is_set_to_add_PAX_headers_for_non_ASCII_names() {
        // Enable POSIX mode for handling non-ASCII names
        tarOutputStream.setLongFileMode(TarConstants.LONGFILE_POSIX);
    }

    @When("I attempt to write a directory entry named {string}")
    public void i_attempt_to_write_a_directory_entry_named(String dirName) {
        try {
            // Create a directory entry with the given name
            entry = new TarArchiveEntry(dirName + "/");
            entry.setMode(0755);  // Set directory permissions
            entry.setSize(0);

            // Write the entry to the stream
            tarOutputStream.putArchiveEntry(entry);
            tarOutputStream.closeArchiveEntry();
        } catch (IOException e) {
            // We catch the exception here for scenarios that expect failure
            throw new RuntimeException(e);
        }
    }

    @Then("the operation should complete without throwing an IOException")
    public void the_operation_should_complete_without_throwing_an_IOException() {
        // This step is implicitly handled by not having an exception thrown in the When step.
        // If an exception occurred, the test framework would catch it.
        // We can add an assertion to ensure we got this far without issues.
        assertTrue("Entry should be created", true);  // Placeholder to show step passed
    }

    @Then("the entry should be successfully written to the archive")
    public void the_entry_should_be_successfully_written_to_the_archive() {
        try {
            tarOutputStream.finish();
            tarOutputStream.close();
            // Check if data was written to the stream
            assertTrue("Archive should contain data", byteArrayOutputStream.size() > 0);
        } catch (IOException e) {
            fail("IOException occurred while finishing archive: " + e.getMessage());
        }
    }

    @Then("the entry should be identified as a directory")
    public void the_entry_should_be_identified_as_a_directory() {
        assertNotNull("Entry should not be null", entry);
        assertTrue("Entry should be a directory", entry.isDirectory());
    }

    @Then("the entry name should be correctly stored as {string}")
    public void the_entry_name_should_be_correctly_stored_as(String expectedName) {
        assertNotNull("Entry should not be null", entry);
        assertEquals("Directory name should match", expectedName + "/", entry.getName());
    }
}

